        background: "#698F8A",
        padding: "12px 10px",
        fontFamily: "Montserrat",
        fontWeight: "600",
        fontSize: "10px",
        lineHeight: "13px",
        color: "#F2FFF5",
        position: "relative",
        color: "#F2FFF5",
        borderLeft: "1px solid",
